<script lang="ts">
	import Badge from "../Badge.svelte";
	import Icon from "../Icon.svelte";
	import Tooltip from "../Tooltip.svelte";
	import type { FileStatus } from "./types";
	import type { ComponentColorType } from "../../utils/colorTypes";

	interface Props {
		status: FileStatus;
		style?: "dot" | "full" | "full-large";
		tooltip?: string;
		color?: string;
	}

	const { status, style = "full", tooltip, color }: Props = $props();

	const TOOLTIP_MAX_WIDTH = 320;

	function getFullStatusText(status: FileStatus): string {
		switch (status) {
			case "addition":
				return "Added";
			case "modification":
				return "Modified";
			case "deletion":
				return "Deleted";
			case "rename":
				return "Renamed";
			default:
				return status;
		}
	}

	function getStatusColor(status: FileStatus): ComponentColorType {
		switch (status) {
			case "addition":
				return "safe";
			case "modification":
				return "warning";
			case "deletion":
				return "danger";
			case "rename":
				return "purple";
			default:
				return "gray";
		}
	}
</script>

{#if style === "dot"}
	<Tooltip text={!tooltip ? getFullStatusText(status) : tooltip} maxWidth={TOOLTIP_MAX_WIDTH}>
		<div
			class="status-dot-wrap"
			style:--custom-file-dot-color={color}
			class:added={status === "addition"}
			class:modified={status === "modification"}
			class:deleted={status === "deletion"}
			class:renamed={status === "rename"}
		>
			{#if status === "addition"}
				<Icon name="change-addition" />
			{:else if status === "modification"}
				<Icon name="change-modification" />
			{:else if status === "deletion"}
				<Icon name="change-deletion" />
			{:else if status === "rename"}
				<Icon name="change-rename" />
			{/if}
		</div>
	</Tooltip>
{:else if style === "full"}
	<Tooltip text={status === "rename" && tooltip ? tooltip : undefined} maxWidth={TOOLTIP_MAX_WIDTH}>
		<Badge style={getStatusColor(status)} kind="soft">{getFullStatusText(status)}</Badge>
	</Tooltip>
{:else if style === "full-large"}
	<Tooltip text={status === "rename" && tooltip ? tooltip : undefined} maxWidth={TOOLTIP_MAX_WIDTH}>
		<Badge style={getStatusColor(status)} kind="soft" size="tag">{getFullStatusText(status)}</Badge>
	</Tooltip>
{/if}

<style>.status-dot-wrap{align-items:center;color:var(--custom-file-dot-color,var(--file-dot-color));display:flex;flex-shrink:0;height:1rem;justify-content:center;width:-moz-fit-content;width:fit-content;width:1rem}.status-dot-wrap.added{--file-dot-color:var(--change-status-addition)}.status-dot-wrap.modified{--file-dot-color:var(--change-status-modification)}.status-dot-wrap.deleted{--file-dot-color:var(--change-status-deletion)}.status-dot-wrap.renamed{--file-dot-color:var(--change-status-rename)}:global(.full-large){height:var(--size-tag)}</style>
