function elementShouldBeExcluded(element, target) {
    if (!element)
        return false;
    if (Array.isArray(element)) {
        return element.some((el) => el.contains(target));
    }
    return element.contains(target);
}
export function clickOutside(node, params) {
    function onClick(event) {
        if (node &&
            !node.contains(event.target) &&
            !elementShouldBeExcluded(params.excludeElement, event.target)) {
            params.handler(event);
        }
    }
    document.addEventListener("pointerdown", onClick, true);
    document.addEventListener("contextmenu", onClick, true);
    return {
        destroy() {
            document.removeEventListener("pointerdown", onClick, true);
            document.removeEventListener("contextmenu", onClick, true);
        },
    };
}
