<script lang="ts">
	import Icon from "../Icon.svelte";

	interface Props {
		searchValue: string;
		placeholder?: string;
	}

	let { placeholder = "Search…", searchValue = $bindable() }: Props = $props();

	let inputEl: HTMLInputElement;

	export function focus() {
		inputEl?.focus();
	}

	function resetFilter() {
		searchValue = "";
		inputEl.focus();
	}

	function handleInput(event: Event) {
		searchValue = (event.target as HTMLInputElement).value;
	}

	function handleKeyDown(event: KeyboardEvent) {
		const { key } = event;

		// Allow arrow keys, Enter, and Escape to bubble up to the parent Select
		// for dropdown navigation while keeping the search input focused
		if (key === "ArrowUp" || key === "ArrowDown" || key === "Enter" || key === "Escape") {
			// Don't prevent default for arrow keys so cursor behavior in input is preserved
			// but don't stop propagation so parent can handle navigation
			return;
		}
	}
</script>

<div class="container">
	{#if !searchValue}
		<i class="icon search-icon">
			<Icon name="search" />
		</i>
	{:else}
		<button type="button" class="icon" onclick={resetFilter}>
			<Icon name="cross-circle" />
		</button>
	{/if}

	<input
		bind:this={inputEl}
		class="text-13 search-input"
		type="text"
		{placeholder}
		bind:value={searchValue}
		oninput={handleInput}
		onkeydown={handleKeyDown}
		autocorrect="off"
		autocomplete="off"
	/>
</div>

<style>.container{position:relative;-webkit-user-select:text;-moz-user-select:text;user-select:text}.search-input{background-color:var(--bg-1);border-bottom:.0625rem solid var(--border-2);color:var(--text-1);padding:.75rem 2.125rem .75rem .75rem;transition:border-color var(--transition-fast);width:100%}.search-input:focus-within,.search-input:hover{background-color:var(--hover-bg-1);outline:none}.search-input::-moz-placeholder{color:var(--text-3)}.search-input::placeholder{color:var(--text-3)}.icon{color:var(--text-2);display:flex;position:absolute;right:.75rem;top:50%;transform:translateY(-50%);transition:color var(--transition-fast)}.icon:hover{color:var(--hover-text-2)}.search-icon{display:flex;pointer-events:none}</style>
