	import type { ComponentColorType } from "../utils/colorTypes";
	import type { Snippet } from "svelte";

	interface Props {
		testId?: string;
		style?: ComponentColorType;
		kind?: "solid" | "soft";
		size?: "icon" | "tag";
		class?: string;
		icon?: IconName;
		tooltip?: string;
		skeleton?: boolean;
		skeletonWidth?: string;
		children?: Snippet;
		onclick?: (e: MouseEvent) => void;
		reversedDirection?: boolean;
	}

	const {
		testId,
		style = "gray",
		kind = "solid",
		size = "icon",
		class: className = "",
		icon,
		tooltip,
		skeleton,
		skeletonWidth,
		children,
		onclick,
		reversedDirection,
	}: Props = $props();
</script>

{#if skeleton}
	<SkeletonBone
		radius="3rem"
		width={skeletonWidth ?? (size === "icon" ? "var(--size-icon)" : "var(--size-tag)")}
		height={size === "icon" ? "var(--size-icon)" : "var(--size-tag)"}
	/>
{:else}
	<Tooltip text={tooltip}>
		<div
			role="presentation"
			data-testid={testId}
			class="badge {style} {kind} {size}-size {className}"
			class:reversed={reversedDirection}
			{onclick}
		>
