<script lang="ts">
	import { focusable } from "../../focus/focusable";
	import type { Snippet } from "svelte";

	interface Props {
		labelFor?: string;
		disabled?: boolean;
		background?: string;
		standalone?: boolean;
		clickable?: boolean;
		alignment?: "top" | "center";
		iconSide?: Snippet;
		title?: Snippet;
		caption?: Snippet;
		children?: Snippet;
		actions?: Snippet;
		onclick?: (e: MouseEvent) => void;
	}

	let {
		labelFor = "",
		disabled = false,
		clickable = false,
		alignment = "top",
		standalone = false,
		background = "var(--bg-1)",
		iconSide,
		title,
		caption,
		children,
		actions,
		onclick,
	}: Props = $props();

	const element = $derived(labelFor ? "label" : "div");
</script>

<svelte:element
	this={element}
	role="presentation"
	for={labelFor || undefined}
	class="card-group-item"
	class:clickable={labelFor !== "" || clickable}
	class:disabled
	class:standalone
	style:background
	use:focusable
	{onclick}
>
	{#if title || caption || iconSide || actions}
		<div class="flex full-width gap-16 hide-when-empty" class:center-align={alignment === "center"}>
			{#if iconSide}
				<div class="card-group-item__icon-side">
					{@render iconSide?.()}
				</div>
			{/if}

			{#if title || caption}
				<div class="card-group-item__content">
					{#if title}
						<h3 class="text-15 text-bold card-group-item__title">
							{@render title?.()}
						</h3>
					{/if}
					{#if caption}
						<p class="text-12 text-body card-group-item__text">
							{@render caption?.()}
						</p>
					{/if}
				</div>
			{/if}

			{#if actions}
				<div class="card-group-item__actions">
					{@render actions?.()}
				</div>
			{/if}
		</div>
	{/if}

	{#if children}
		<div class="stack-v gap-16 hide-when-empty">
			{@render children?.()}
		</div>
	{/if}
</svelte:element>

