<script lang="ts">
	import Icon from "../Icon.svelte";
	import { focusable } from "../../focus/focusable";
	import { type IconName } from "../../icons/names";
	import type { Snippet } from "svelte";

	interface Props {
		icon?: IconName;
		iconSnippet?: Snippet;
		selected?: boolean;
		disabled?: boolean;
		loading?: boolean;
		highlighted?: boolean;
		value?: string | undefined;
		testId?: string;
		children?: Snippet;
		onClick?: (value: string | undefined) => void;
	}

	const {
		icon = undefined,
		iconSnippet,
		selected = false,
		disabled = false,
		loading = false,
		highlighted = false,
		value = undefined,
		testId,
		onClick,
		children,
	}: Props = $props();

	let self = $state<HTMLButtonElement>();
</script>

<button
	bind:this={self}
	data-testid={testId}
	type="button"
	{disabled}
	class="select-button"
	class:selected
	class:highlighted
	use:focusable={{ button: true, onAction: () => self?.click() }}
	onclick={() => onClick?.(value)}
>
	{#if iconSnippet}
		<div class="custom-icon">
			{@render iconSnippet()}
		</div>
	{/if}
	<div class="label text-13">
		{@render children?.()}
	</div>
	{#if icon || selected}
		<div class="icon">
			{#if icon}
				<Icon name={loading ? "spinner" : icon} />
			{:else}
				<Icon name="tick" />
			{/if}
		</div>
	{/if}
</button>

<style>.select-button{align-items:center;border-radius:var(--radius-m);color:var(--text-1);display:flex;gap:.625rem;padding:.5rem;-webkit-user-select:none;-moz-user-select:none;user-select:none;white-space:nowrap;width:100%}.select-button:not(.selected):focus:enabled,.select-button:not(.selected):hover:enabled{background-color:var(--hover-bg-1)}.select-button:disabled{opacity:.4}.select-button .custom-icon,.select-button .icon{color:var(--text-2);display:flex;flex-shrink:0}.select-button .label{display:block;flex:1;overflow:hidden;text-align:left;text-overflow:ellipsis;white-space:nowrap}.selected{background-color:var(--bg-2)}.selected .label{opacity:.5}.highlighted:not(.selected){background-color:var(--hover-bg-1)}</style>
