<script lang="ts">
	import Badge from "../Badge.svelte";
	import Button from "../Button.svelte";
	import Icon from "../Icon.svelte";
	import LineStats from "../LineStats.svelte";
	import ExecutableLabel from "./ExecutableLabel.svelte";
	import FileName from "./FileName.svelte";
	import FileStatusBadge from "./FileStatusBadge.svelte";
	import type { FileStatus } from "./types";

	interface Props {
		id?: string;
		filePath: string;
		fileStatus?: FileStatus;
		fileStatusTooltip?: string;
		draggable?: boolean;
		linesAdded?: number;
		linesRemoved?: number;
		conflicted?: boolean;
		executable?: boolean;
		noPaddings?: boolean;
		pathFirst?: boolean;
		class?: string;
		oncontextmenu?: (e: MouseEvent) => void;
		oncloseclick?: () => void;
	}

	const {
		id,
		filePath,
		fileStatus,
		fileStatusTooltip,
		draggable,
		linesAdded = 0,
		linesRemoved = 0,
		conflicted,
		executable,
		noPaddings,
		pathFirst = true,
		class: className,
		oncontextmenu,
		oncloseclick,
	}: Props = $props();
</script>

<div
	role="presentation"
	{id}
	class="file-header {className}"
	class:draggable
	class:no-paddings={noPaddings}
	oncontextmenu={(e) => {
		if (oncontextmenu) {
			e.preventDefault();
			e.stopPropagation();
			oncontextmenu(e);
		}
	}}
>
	{#if draggable}
		<div class="file-header__drag-handle">
			<Icon name="drag-vertical" />
		</div>
	{/if}

	<div class="file-header__name">
		<FileName {filePath} {pathFirst} textSize="13" />
	</div>

	<div class="file-header__statuses">
		{#if linesAdded > 0 || linesRemoved > 0}
			<LineStats {linesAdded} {linesRemoved} />
		{/if}

		{#if executable}
			<ExecutableLabel />
		{/if}

		{#if fileStatus}
			<FileStatusBadge tooltip={fileStatusTooltip} status={fileStatus} style="full" />
		{/if}

		{#if conflicted}
			<Badge size="icon" style="danger">Has conflicts</Badge>
		{/if}
	</div>

	{#if oncloseclick}
		<Button
			class="file-header__close-btn"
			kind="ghost"
			size="tag"
			icon="cross"
			onclick={oncloseclick}
		/>
	{/if}
</div>

<style>.file-header{align-items:center;display:flex;gap:.75rem;overflow:hidden;width:100%;z-index:var(--z-lifted)}.file-header.draggable{cursor:grab}.file-header.no-paddings{padding:0}.file-header__statuses{align-items:center;display:flex;gap:.375rem}.file-header__name{align-items:center;display:flex;overflow:hidden}.file-header__drag-handle{align-items:center;color:var(--text-3);display:flex;justify-content:center;margin-left:-.375rem;margin-right:-.375rem}</style>
