<script lang="ts">
	import profileIconSvg from "../../assets/profile-icon.svg?raw";
	import { useImageLoading } from "../../utils/imageLoading.svelte";

	interface Props {
		onclick: () => void;
		srcUrl?: string | null;
	}

	const { onclick, srcUrl }: Props = $props();

	const placeholderUrl = `data:image/svg+xml;utf8,${encodeURIComponent(profileIconSvg)}`;
	const imageLoadingState = useImageLoading();
</script>

<button
	type="button"
	class="profile-btn"
	class:has-image={!!srcUrl}
	aria-label="Profile button"
	onclick={async () => onclick()}
>
	{#if srcUrl && !imageLoadingState.hasError}
		<img
			bind:this={imageLoadingState.imgElement}
			src={srcUrl}
			alt="Profile"
			class="hidden-preload"
			referrerpolicy="no-referrer"
			onload={imageLoadingState.handleImageLoad}
			onerror={imageLoadingState.handleImageError}
		/>
	{/if}
	<div
		class="profile-image"
		class:loaded={imageLoadingState.imageLoaded || !srcUrl || imageLoadingState.hasError}
		style:background-image={srcUrl && !imageLoadingState.hasError
			? `url(${srcUrl})`
			: `url("${placeholderUrl}")`}
	></div>
</button>

<style>.profile-btn{align-items:center;aspect-ratio:1/1;background:var(--fill-pop-bg);border-radius:50%;cursor:pointer;display:flex;overflow:hidden;transition:background-color var(--transition-medium);width:2.125rem}.profile-btn.has-image:hover,.profile-btn:not(.has-image):hover{background-color:var(--hover-pop)}.profile-btn.has-image:hover .profile-image{filter:brightness(.9)}.profile-image{background-position:50%;background-size:cover;border-radius:50%;height:100%;opacity:0;transition:filter var(--transition-medium),opacity .2s ease-in;width:100%}.profile-image.loaded{opacity:1}.hidden-preload{height:.0625rem;opacity:0;pointer-events:none;position:absolute;width:.0625rem}</style>
