<script lang="ts">
	import Checkbox from "../Checkbox.svelte";
	import Icon from "../Icon.svelte";
	import FileIcon from "./FileIcon.svelte";
	import FileIndent from "./FileIndent.svelte";
	import { type FocusableOptions } from "../../focus/focusTypes";
	import { focusable } from "../../focus/focusable";

	interface Props {
		name: string;
		showCheckbox?: boolean;
		checked?: boolean;
		indeterminate?: boolean;
		isExpanded?: boolean;
		depth?: number;
		transparent?: boolean;
		draggable?: boolean;
		selected?: boolean;
		active?: boolean;
		actionOpts?: FocusableOptions;
		oncheck?: (
			e: Event & {
				currentTarget: EventTarget & HTMLInputElement;
			},
		) => void;
		ontoggle?: (expanded: boolean) => void;
		onclick?: (e: MouseEvent) => void;
		onkeydown?: (e: KeyboardEvent) => void;
		onmousedown?: (e: MouseEvent) => void;
		oncontextmenu?: (e: MouseEvent) => void;
		testId?: string;
	}

	let {
		name,
		showCheckbox,
		checked = $bindable(),
		indeterminate,
		isExpanded = $bindable(true),
		depth,
		transparent,
		draggable = false,
		selected = false,
		active = false,
		actionOpts,
		oncheck,
		ontoggle,
		onclick,
		onkeydown,
		onmousedown,
		oncontextmenu,
		testId,
	}: Props = $props();
</script>

<div
	data-testid={testId}
	class="folder-list-item"
	role="option"
	aria-selected={selected}
	tabindex="0"
	class:transparent
	class:draggable
	class:selected
	class:active
	use:focusable={actionOpts}
	{onmousedown}
	onclick={(e) => {
		e.stopPropagation();
		onclick?.(e);
	}}
	{onkeydown}
	oncontextmenu={(e) => {
		if (oncontextmenu) {
			e.preventDefault();
			e.stopPropagation();
			oncontextmenu(e);
		}
	}}
>
	{#if draggable && !showCheckbox}
		<div class="draggable-handle">
			<Icon name="drag-vertical" />
		</div>
	{/if}

	<div class="folder-list-item__indicators">
		<FileIndent {depth} />

		<button
			type="button"
			aria-label="Toggle folder"
			class="folder-list-item__arrow"
			class:expanded={isExpanded}
			onclick={(e) => {
				e.stopPropagation();
				isExpanded = !isExpanded;
				ontoggle?.(isExpanded);
			}}
		>
			<svg
				width="10"
				height="6"
				viewBox="0 0 10 6"
				fill="currentColor"
				xmlns="http://www.w3.org/2000/svg"
			>
				<path
					fill-rule="evenodd"
					clip-rule="evenodd"
					d="M5.17683 3.76259C5.0792 3.86022 4.92091 3.86022 4.82328 3.76259L1.53039 0.469698L0.469727 1.53036L3.76262 4.82325C4.44604 5.50667 5.55408 5.50667 6.23749 4.82325L9.53039 1.53036L8.46973 0.469698L5.17683 3.76259Z"
				/>
			</svg>
		</button>

		{#if showCheckbox}
			<Checkbox small bind:checked {indeterminate} onchange={oncheck} />
		{/if}

		<div class="folder-list-item__icon">
			<FileIcon fileName={isExpanded ? "folder-open" : "folder-close"} />
		</div>
	</div>
	<p class="text-12 text-semibold truncate">{name}</p>
</div>

<style>.folder-list-item{align-items:center;background-color:var(--bg-1);cursor:pointer;display:flex;gap:.5rem;height:1.875rem;padding:0 .5rem 0 .875rem;position:relative}.folder-list-item:not(.selected):hover{background-color:var(--hover-bg-1)}.folder-list-item.transparent{background-color:transparent}.folder-list-item.selected{background-color:var(--focus-bg-mute)}.folder-list-item.selected:hover{background-color:color-mix(in srgb,var(--focus-bg-mute) 96%,var(--fill-gray-bg))}.folder-list-item.active.selected{background-color:var(--focus-bg)}.folder-list-item.active.selected:hover{background-color:color-mix(in srgb,var(--focus-bg) 95%,var(--fill-pop-bg))}.folder-list-item:focus-visible{background-color:var(--focus-bg);outline:none}.folder-list-item .draggable-handle{align-items:center;color:var(--text-2);display:none;justify-content:center;left:.25rem;opacity:.6;position:absolute;width:.375rem}.folder-list-item.draggable:hover .draggable-handle{display:flex}.folder-list-item__indicators{align-items:center;color:var(--text-2);display:flex;gap:.375rem;height:100%}.folder-list-item__arrow{align-items:center;border-radius:var(--radius-s);display:flex;height:.875rem;justify-content:center;margin:0 -.125rem;transform:rotate(-90deg);width:.875rem}.folder-list-item__arrow:hover{color:var(--text-1)}.folder-list-item__arrow.expanded{transform:rotate(0);transition:transform var(--transition-fast)}.folder-list-item__icon{align-items:center;color:var(--text-2);display:flex;justify-content:center;margin-left:.125rem}</style>
