<script lang="ts">
	import Badge from "../Badge.svelte";
	import Button from "../Button.svelte";
	import Checkbox from "../Checkbox.svelte";
	import Icon from "../Icon.svelte";
	import Tooltip from "../Tooltip.svelte";
	import AvatarGroup from "../avatar/AvatarGroup.svelte";
	import ExecutableLabel from "./ExecutableLabel.svelte";
	import FileIndent from "./FileIndent.svelte";
	import FileName from "./FileName.svelte";
	import FileStatusBadge from "./FileStatusBadge.svelte";
	import { focusable } from "../../focus/focusable";
	import type { FileStatus } from "./types";
	import type { FocusableOptions } from "../../focus/focusTypes";

	interface Props {
		ref?: HTMLDivElement;
		id?: string;
		filePath: string;
		fileStatus?: FileStatus;
		fileStatusTooltip?: string;
		fileStatusStyle?: "dot" | "full";
		pathFirst?: boolean;
		draggable?: boolean;
		selected?: boolean;
		focused?: boolean;
		clickable?: boolean;
		showCheckbox?: boolean;
		listMode?: "list" | "tree";
		depth?: number;
		checked?: boolean;
		indeterminate?: boolean;
		conflicted?: boolean;
		conflictHint?: string;
		locked?: boolean;
		lockText?: string;
		active?: boolean;
		executable?: boolean;
		isLast?: boolean;
		actionOpts?: FocusableOptions;
		notched?: boolean;
		ircWorkingUsers?: string[];
		oncheckclick?: (e: MouseEvent) => void;
		oncheck?: (
			e: Event & {
				currentTarget: EventTarget & HTMLInputElement;
			},
		) => void;
		onclick?: (e: MouseEvent) => void;
		ondblclick?: (e: MouseEvent) => void;
		onresolveclick?: (e: MouseEvent) => void;
		onkeydown?: (e: KeyboardEvent) => void;
		oncontextmenu?: (e: MouseEvent) => void;
		onlockhover?: () => void;
		onlockunhover?: () => void;
	}

	let {
		ref = $bindable(),
		id,
		filePath,
		fileStatus,
		fileStatusTooltip,
		fileStatusStyle = "dot",
		pathFirst = true,
		draggable = false,
		selected = false,
		focused = false,
		clickable = true,
		showCheckbox = false,
		checked = $bindable(),
		indeterminate,
		conflicted,
		conflictHint,
		locked,
		lockText,
		active,
		listMode = "list",
		depth,
		executable,
		isLast = false,
		actionOpts,
		notched,
		ircWorkingUsers,
		oncheck,
		oncheckclick,
		onclick,
		ondblclick,
		onresolveclick,
		onkeydown,
		oncontextmenu,
		onlockhover,
		onlockunhover,
	}: Props = $props();

	const showIndent = $derived(depth && depth > 0);
</script>

<div
	bind:this={ref}
	{id}
	data-locked={locked}
	data-file-id={id}
	class="file-list-item"
	class:selected
	class:active
	class:clickable
	class:focused
	class:draggable
	class:conflicted
	class:notched
	class:list-mode={listMode === "list"}
	class:is-last={isLast}
	aria-selected={selected}
	role="option"
	tabindex="0"
	{onclick}
	{ondblclick}
	{onkeydown}
	use:focusable={actionOpts}
	oncontextmenu={(e) => {
		if (oncontextmenu) {
			e.preventDefault();
			e.stopPropagation();
			oncontextmenu(e);
		}
	}}
>
	{#if draggable && !showCheckbox && !notched}
		<div class="draggable-handle">
			<Icon name="drag-vertical" />
		</div>
	{/if}

	{#if notched}
		<div class="commit-row__notch"></div>
	{/if}

	{#if showIndent || showCheckbox}
		<div class="file-list-item__indicators">
			{#if showIndent}
				<FileIndent {depth} />
			{/if}

			{#if showCheckbox}
				<Checkbox small {checked} {indeterminate} onchange={oncheck} onclick={oncheckclick} />
			{/if}
		</div>
	{/if}

	<FileName {filePath} hideFilePath={listMode === "tree"} {pathFirst} />

	<div class="file-list-item__details">
		{#if ircWorkingUsers && ircWorkingUsers.length > 0}
			<AvatarGroup
				avatars={ircWorkingUsers.map((nick) => ({
					srcUrl: `https://github.com/${encodeURIComponent(nick)}.png?size=32`,
					username: nick,
				}))}
				maxAvatars={3}
				size="small"
			/>
		{/if}

		{#if executable}
			<ExecutableLabel />
		{/if}

		{#if conflicted}
			<Tooltip text={conflictHint}>
				<div class="conflicted-icon">
					<Icon name="warning" />
				</div>
			</Tooltip>
		{:else if fileStatus}
			<FileStatusBadge tooltip={fileStatusTooltip} status={fileStatus} style={fileStatusStyle} />
		{/if}

		{#if locked}
			<Tooltip text={lockText}>
				<div
					class="locked"
					role="img"
					aria-label="File is locked due to dependencies"
					onmouseenter={() => onlockhover?.()}
					onmouseleave={() => onlockunhover?.()}
				>
					<Icon name="lock" />
				</div>
			</Tooltip>
		{/if}

		{#if onresolveclick}
			{#if !conflicted}
				<Tooltip text="Conflict resolved">
					<Badge style="safe">Resolved</Badge>
				</Tooltip>
			{:else}
				<Button
					type="button"
					class="m-l-4 m-r-4"
					size="tag"
					onclick={(e) => {
						e.stopPropagation();
						onresolveclick?.(e);
					}}
					icon="tick"
				>
					Mark resolved
				</Button>
			{/if}
		{/if}
	</div>
</div>

<style>.file-list-item{align-items:center;background-color:var(--bg-1);display:flex;gap:.5rem;height:1.875rem;padding:0 .5rem 0 .875rem;position:relative;text-align:left;-webkit-user-select:none;-moz-user-select:none;user-select:none}.file-list-item:focus-visible{outline:none}.file-list-item.list-mode{border-bottom:.0625rem solid var(--border-3)}.file-list-item.list-mode.is-last{border-bottom:none}.file-list-item.clickable{cursor:pointer}.file-list-item.clickable:hover .draggable-handle{display:flex}.file-list-item.clickable:not(.selected):hover{background-color:var(--hover-bg-1)}.file-list-item.clickable.conflicted:not(.selected):hover{background-color:var(--hover-danger-bg)}.file-list-item.conflicted{background-color:var(--bg-danger)}.file-list-item.conflicted.selected{background-color:var(--fill-danger-bg)}.file-list-item.selected{background-color:var(--focus-bg-mute)}.file-list-item.selected.list-mode{border-bottom:.0625rem solid color-mix(in srgb,var(--focus-bg-mute) 90%,var(--text-1))}.file-list-item.selected.list-mode.is-last{border-bottom:none}.file-list-item.selected:hover{background-color:color-mix(in srgb,var(--focus-bg-mute) 96%,var(--fill-gray-bg))}.file-list-item.active.selected{background-color:var(--focus-bg)}.file-list-item.active.selected.list-mode{border-bottom:.0625rem solid color-mix(in srgb,var(--focus-bg) 90%,var(--text-1))}.file-list-item.active.selected:hover{background-color:color-mix(in srgb,var(--focus-bg) 95%,var(--fill-pop-bg))}.file-list-item.active.selected.list-mode.is-last{border-bottom:none}.file-list-item.active.selected .conflicted-icon{color:var(--fill-pop-fg)}.file-list-item .draggable-handle{align-items:center;color:var(--text-2);display:none;justify-content:center;left:.25rem;opacity:.6;position:absolute;top:50%;transform:translateY(-50%);width:.375rem}.file-list-item .conflicted-icon{color:var(--fill-danger-bg);display:flex;margin-right:-.125rem}.file-list-item__indicators{align-items:center;display:flex;gap:.375rem;height:100%}.commit-row__notch{background-color:var(--border-2);height:calc(100% + .125rem);left:0;position:absolute;top:-.0625rem;width:.1875rem}.file-list-item__details{align-items:center;display:flex;flex-grow:1;gap:.25rem}.file-list-item__details .locked{color:var(--change-status-modification);display:flex}</style>
