<script lang="ts" module>
	type T = any | unknown | undefined;

	export type ModalSize = "medium" | "large" | "small" | "xsmall" | "full-screen" | number;
	export type ModalType = "info" | "warning" | "danger" | "success";

	export type ModalProps = {
		width?: ModalSize;
		type?: ModalType;
		title?: string;
		closeButton?: boolean;
		noPadding?: boolean;
		defaultItem?: T;
		preventCloseOnClickOutside?: boolean;
		/**
		 * Callback to be called when the modal is closed.
		 *
		 * Whether closing by clicking outside the modal, subtmitting the form or calling the `close` function.
		 * This is called after the closing animation is finished.
		 */
		onClose?: () => void;
		/**
		 * Callback to be called when the modal is closed by clicking outside the modal.
		 */
		onClickOutside?: () => void;
		onSubmit?: (close: () => void, item: T) => void;
		onKeyDown?: (e: KeyboardEvent) => void;
		children: Snippet<[item: T, close: () => void]>;
		controls?: Snippet<[close: () => void, item: T]>;
		testId?: string;
	};
</script>

<script lang="ts" generics="T extends undefined | any = any">
	import ModalFooter from "./ModalFooter.svelte";
	import ModalHeader from "./ModalHeader.svelte";
	import { focusable } from "../focus/focusable";
	import { portal } from "../utils/portal";
	import { pxToRem } from "../utils/pxToRem";
	import { onDestroy, untrack } from "svelte";
	import type { Snippet } from "svelte";

	const {
		width = "medium",
		title,
		type = "info",
		closeButton,
		onClose,
		onClickOutside,
		preventCloseOnClickOutside,
		children,
		controls,
		onSubmit,
		onKeyDown,
		noPadding = false,
		testId,
		defaultItem,
	}: ModalProps = $props();

	let open = $state(false);
	let item = $state<T>(untrack(() => defaultItem) as any);
	let isClosing = $state(false);
	let closingPromise: Promise<void> | undefined = undefined;
	let formEl: HTMLFormElement | undefined = $state();

	function handleKeyDown(event: KeyboardEvent) {
		if (event.key === "Escape") {
			close();
		}
		if (event.key === "Enter") {
			const target = event.target;
			const isNativeSubmitElement =
				target instanceof HTMLInputElement ||
				target instanceof HTMLTextAreaElement ||
				target instanceof HTMLButtonElement ||
				(target instanceof HTMLElement && target.isContentEditable);
			if (!isNativeSubmitElement) {
				event.preventDefault();
				// Click the submit button if one exists (triggers AsyncButton loading state).
				const submitBtn = formEl?.querySelector<HTMLButtonElement>('button[type="submit"]');
				if (submitBtn) {
					submitBtn.click();
				} else {
					onSubmit?.(close, item);
				}
			}
		}
	}

	// Clean up event listener if component is destroyed (in case modal is open)
	onDestroy(() => {
		window.removeEventListener("keydown", handleKeyDown);
	});

	export function show(newItem?: T) {
		item = newItem as any;
		open = true;

		window.addEventListener("keydown", handleKeyDown);
	}

	export function close(): Promise<void> {
		if (!open) return Promise.resolve();
		if (isClosing && closingPromise) return closingPromise;

		window.removeEventListener("keydown", handleKeyDown);

		isClosing = true;
		closingPromise = new Promise((resolve) => {
			setTimeout(() => {
				item = undefined as any;
				open = false;
				isClosing = false;
				onClose?.();
				closingPromise = undefined;
				resolve();
			}, 100); // This should match the duration of the closing animation
		});

		return closingPromise;
	}

	export const imports = {
		get open() {
			return open;
		},
	};
</script>

{#if open}
	<div
		data-testid={testId}
		role="presentation"
		use:portal={"body"}
		class="modal-container {isClosing ? 'closing' : 'open'}"
		class:open
		onmousedown={(e) => {
			e.stopPropagation();

			if (preventCloseOnClickOutside) return;

			if (e.target === e.currentTarget) {
				onClickOutside?.();
				close();
			}
		}}
		onkeydown={onKeyDown}
	>
		<form
			bind:this={formEl}
			class="modal-form"
			class:medium={width === "medium"}
			class:large={width === "large"}
			class:small={width === "small"}
			class:xsmall={width === "xsmall"}
			class:full-screen={width === "full-screen"}
			style:width={typeof width === "number" ? `${pxToRem(width)}rem` : undefined}
			use:focusable={{
				trap: true,
				activate: true,
				focusable: true,
				dim: true,
				onEsc: () => {
					close();
					return true;
				},
			}}
			onsubmit={(e) => {
				e.preventDefault();
				onSubmit?.(close, item);
			}}
		>
			{#if title}
				<ModalHeader {type} {closeButton} oncloseclick={close}>
					{title}
				</ModalHeader>
			{/if}

			<div
				class="modal__body text-13 text-body"
				class:padding-top={!title}
				class:no-padding={noPadding}
			>
				{#if children}
					{@render children(item, close)}
				{/if}
			</div>

			{#if controls}
				<ModalFooter>
					{@render controls(close, item)}
				</ModalFooter>
			{/if}
		</form>
	</div>
{/if}

