<script lang="ts" module>
	export interface Props {
		id?: string | undefined;
		el?: HTMLElement;
		// Interaction props
		disabled?: boolean;
		loading?: boolean;
		activated?: boolean;
		tabindex?: number | undefined;
		type?: "submit" | "reset" | "button" | undefined;
		autofocus?: boolean;
		// Layout props
		shrinkable?: boolean;
		reversedDirection?: boolean;
		width?: number | string | undefined;
		size?: "tag" | "button";
		wide?: boolean;
		grow?: boolean;
		align?: "flex-start" | "center" | "flex-end" | "stretch" | "baseline" | "auto";
		dropdownChild?: boolean;
		// Style props
		style?: ComponentColorType;
		kind?: ComponentKindType;
		class?: string | (string | undefined)[] | Record<string, string>;
		iconClass?: string;
		customStyle?: string;
		// Additional elements
		icon?: IconName;
		isDropdown?: boolean;
		dropdownOpen?: boolean;
		hotkey?: string;
		tooltip?: string;
		tooltipPosition?: TooltipPosition;
		tooltipAlign?: TooltipAlign;
		tooltipDelay?: number;
		testId?: string;
		// Events
		onclick?: ((e: MouseEvent) => Promise<void>) | ((e: MouseEvent) => void);
		onmousedown?: (e: MouseEvent) => void;
		oncontextmenu?: (e: MouseEvent) => void;
		onkeydown?: (e: KeyboardEvent) => void;
		// Snippets
		children?: Snippet;
		custom?: Snippet;
		badge?: Snippet;
	}
</script>

<script lang="ts">
	import Icon from "./Icon.svelte";
	import Tooltip, { type TooltipAlign, type TooltipPosition } from "./Tooltip.svelte";
	import { focusable } from "../focus/focusable";
	import { type IconName } from "../icons/names";
	import { formatHotkeyForPlatform } from "../utils/hotkeySymbols";
	import { pxToRem } from "../utils/pxToRem";
	import { onMount, tick } from "svelte";
	import type { ComponentColorType, ComponentKindType } from "../utils/colorTypes";
	import type { Snippet } from "svelte";

	let {
		el = $bindable(),
		disabled = false,
		id = undefined,
		loading = false,
		activated = false,
		tabindex,
		type = "button",
		autofocus = false,
		shrinkable = false,
		reversedDirection = false,
		width,
		size = "button",
		wide = false,
		grow = false,
		align = "auto",
		dropdownChild = false,
		style = "gray",
		kind = "solid",
		hotkey,
		class: className = "",
		iconClass = "",
		customStyle,
		testId,
		icon,
		isDropdown = false,
		dropdownOpen = false,
		tooltip,
		tooltipPosition,
		tooltipAlign,
		tooltipDelay,
		onclick,
		onmousedown: onmousedownExternal,
		oncontextmenu,
		onkeydown,
		children,
		custom,
		badge,
	}: Props = $props();

	async function handleAction(e: MouseEvent) {
		if (loading || disabled) {
			e.preventDefault();
			e.stopPropagation();
			return;
		}

		await onclick?.(e);
	}

	const hasChildren = $derived(Boolean(children));
	const isDisabled = $derived(disabled || loading);
	const resolvedWidth = $derived(
		width !== undefined ? (typeof width === "number" ? `${pxToRem(width)}rem` : width) : undefined,
	);

	const buttonClasses = $derived([
		"btn",
		style,
		kind,
		size && `${size}-size`,
		activated && "activated",
		grow && "grow",
		wide && "wide",
		shrinkable && "shrinkable",
		reversedDirection && "reversed-direction",
		dropdownChild && "is-dropdown",
		!hasChildren && !wide && "fixed-width",
		className,
	]);

	const displayHotkey = $derived(hotkey ? formatHotkeyForPlatform(hotkey) : undefined);
	const iconSize = $derived(size === "tag" ? 14 : 16);
	let tooltipInstance = $state<Tooltip>();

	function onmousedown(e: MouseEvent) {
		tooltipInstance?.dismiss();
		onmousedownExternal?.(e);
	}

	onMount(() => {
		if (autofocus) {
			tick().then(() => {
				el?.focus();
			});
		}
	});
</script>

<Tooltip
	bind:this={tooltipInstance}
	text={tooltip}
	align={tooltipAlign}
	position={tooltipPosition}
	delay={tooltipDelay}
	hotkey={displayHotkey}
>
	<button
		bind:this={el}
		use:focusable={{
			button: true,
			hotkey: hotkey,
			onAction: () => {
				el?.click();
			},
		}}
		class={buttonClasses}
		style:align-self={align}
		style:width={resolvedWidth}
		style={customStyle}
		disabled={isDisabled}
		onclick={handleAction}
		{onmousedown}
		{oncontextmenu}
		{onkeydown}
		{type}
		{id}
		{tabindex}
		{...testId ? { "data-testid": testId } : {}}
	>
		{#if children}
			<span class="btn-label text-semibold truncate text-12">
				{@render children()}

				{#if displayHotkey}
					<span class="btn-hotkey">
						{displayHotkey}
					</span>
				{/if}
				{#if badge}
					<span class="btn-badge">
						{@render badge()}
					</span>
				{/if}
			</span>
		{/if}

		{#if icon || loading || isDropdown}
			<div class={["btn-icon", iconClass]}>
				{#if loading}
					<Icon name="spinner" size={iconSize} />
				{:else if isDropdown}
					<div class="btn-dropdown-chevron" class:open={dropdownOpen}>
						<Icon name="chevron-down" size={iconSize} />
					</div>
				{:else if icon}
					<Icon name={icon} size={iconSize} />
				{/if}
			</div>
		{/if}

		{#if custom}
			{@render custom()}
		{/if}
	</button>
</Tooltip>

