<script lang="ts">
	import Button from "./Button.svelte";
	import Icon from "./Icon.svelte";
	import { type ModalType } from "./Modal.svelte";
	import { type Snippet } from "svelte";

	interface Props {
		type?: ModalType;
		closeButton?: boolean;
		sticky?: boolean;
		closeButtonTestId?: string;
		children: Snippet;
		oncloseclick?: () => void;
	}

	const {
		type = "info",
		closeButton,
		sticky,
		closeButtonTestId,
		children,
		oncloseclick,
	}: Props = $props();
</script>

<div class="modal__header" class:sticky>
	{#if type === "warning"}
		<Icon name="warning" color="var(--fill-warn-bg)" />
	{/if}

	{#if type === "danger"}
		<Icon name="danger" color="var(--fill-danger-bg)" />
	{/if}

	{#if type === "success"}
		<Icon name="tick-circle" color="var(--fill-safe-bg)" />
	{/if}

	<h2 class="text-14 text-bold">
		{@render children()}
	</h2>

	{#if closeButton}
		<div class="close-btn">
			<Button
				type="button"
				testId={closeButtonTestId}
				kind="ghost"
				icon="cross"
				onclick={oncloseclick}
			></Button>
		</div>
	{/if}
</div>

<style>.modal__header{align-items:center;background-color:var(--bg-1);display:flex;gap:.5rem;padding:1rem;position:relative}.modal__header.sticky{border-bottom:.0625rem solid var(--border-2)}.close-btn{position:absolute;right:.625rem;top:.625rem}</style>
