<script lang="ts">
	import { focusable } from "../focus/focusable";

	interface Props {
		small?: boolean;
		disabled?: boolean;
		checked?: boolean;
		value?: string;
		id?: string;
		testId?: string;
		onclick?: (e: MouseEvent) => void;
		onchange?: (checked: boolean) => void;
	}

	let {
		testId,
		small,
		disabled,
		checked = $bindable(),
		value,
		id,
		onclick,
		onchange,
	}: Props = $props();
</script>

<input
	data-testid={testId}
	bind:checked
	onclick={(e) => {
		e.stopPropagation();
		onclick?.(e);
	}}
	onchange={(e) => onchange?.(e.currentTarget.checked)}
	onkeydown={(e) => {
		// Prevent Enter key from submitting forms, but manually toggle the checkbox
		if (e.key === "Enter") {
			e.preventDefault();
			const target = e.currentTarget;
			target.checked = !target.checked;
			onchange?.(target.checked);
		}
	}}
	type="checkbox"
	class="toggle"
	class:small
	{value}
	{id}
	{disabled}
	use:focusable={{ button: true }}
/>

