<script lang="ts">
	import Icon from "./Icon.svelte";
	import { type IconName } from "../icons/names";
	import { keysStringToArr } from "../utils/hotkeys";
	import { getContext } from "svelte";
	import type { Snippet } from "svelte";

	// Context key for submenu coordination
	const SUBMENU_CONTEXT_KEY = "contextmenu-submenu-coordination";

	interface Props {
		icon?: IconName;
		emoji?: string;
		label: string;
		disabled?: boolean;
		selected?: boolean;
		control?: Snippet;
		keyboardShortcut?: string;
		caption?: string;
		onclick: (e: MouseEvent) => void;
		testId?: string;
	}

	const {
		onclick,
		icon,
		emoji,
		label,
		disabled,
		selected = false,
		control,
		keyboardShortcut,
		caption,
		testId,
	}: Props = $props();

	// Get submenu coordination context if available
	const submenuCoordination:
		| {
				closeAll: () => void;
				hasOpenSubmenus: () => boolean;
				getMenuContainer: () => HTMLElement | undefined;
				getMenuId: () => string;
				closeEntireMenu: () => void;
		  }
		| undefined = getContext(SUBMENU_CONTEXT_KEY);

	function handleMouseEnter() {
		// Close any open submenus when hovering over a regular menu item
		submenuCoordination?.closeAll();
	}

	function handleClick(e: MouseEvent) {
		if (disabled) return;
		e.stopPropagation();
		onclick(e);
	}
</script>

<button
	data-testid={testId}
	type="button"
	class="menu-item no-select"
	style:--item-height={caption ? "auto" : "1.625rem"}
	class:disabled
	{disabled}
	onclick={handleClick}
	onmouseenter={handleMouseEnter}
>
	<div class="menu-item__content">
		{#if emoji}
			<div class="text-12">
				{emoji}
			</div>
		{:else if icon}
			<div class="menu-item__icon">
				<Icon name={icon} />
			</div>
		{/if}

		<span class="menu-item__label text-12">
			{label}
		</span>
		{#if keyboardShortcut}
			<span class="menu-item__shortcut text-12">
				{#each keysStringToArr(keyboardShortcut) as key}
					<span>{key}</span>
				{/each}
			</span>
		{/if}
		{#if control}
			{@render control()}
		{:else if selected}
			<div class="menu-item__icon">
				<Icon name="tick" />
			</div>
		{/if}
	</div>
	{#if caption}
		<div class="text-11 text-body menu-item__caption">
			{caption}
		</div>
	{/if}
</button>

