<script lang="ts">
	import { focusable } from "../focus/focusable";
	import { pxToRem } from "../utils/pxToRem";

	interface Props {
		element?: HTMLInputElement;
		id?: string;
		testId?: string;
		value?: number;
		min?: number;
		max?: number;
		step?: number;
		label?: string;
		helperText?: string;
		error?: string;
		disabled?: boolean;
		showValue?: boolean;
		wide?: boolean;
		width?: number;
		oninput?: (val: number) => void;
		onchange?: (val: number) => void;
	}

	let {
		element = $bindable(),
		id,
		testId,
		value = $bindable(0),
		min = 0,
		max = 100,
		step = 1,
		label,
		helperText,
		error,
		disabled,
		showValue = false,
		wide,
		width,
		oninput,
		onchange,
	}: Props = $props();

	// Calculate the fill ratio (0-1)
	let fillRatio = $derived((value - min) / (max - min));
</script>

<div
	class="range-input"
	class:wide
	class:error={!!error}
	style:width={width ? `${pxToRem(width)}rem` : undefined}
>
	{#if label}
		<div class="label-wrap">
			<label class="label text-13 text-semibold" for={id}>
				{label}
			</label>
			{#if showValue}
				<span class="value text-13 text-semibold">{value}</span>
			{/if}
		</div>
	{/if}

	<input
		bind:this={element}
		{id}
		data-testid={testId}
		type="range"
		class="input"
		{min}
		{max}
		{step}
		{disabled}
		bind:value
		use:focusable={{ button: true }}
		style:--fill-ratio={fillRatio}
		oninput={(e) => {
			oninput?.(parseFloat(e.currentTarget.value));
		}}
		onchange={(e) => {
			onchange?.(parseFloat(e.currentTarget.value));
		}}
	/>

	{#if error}
		<p class="text-11 text-body error-text">{error}</p>
	{:else if helperText}
		<p class="text-11 text-body helper-text">{helperText}</p>
	{/if}
</div>

