export function removeFromArray(array, item) {
    const index = array.indexOf(item);
    if (index !== -1) {
        array.splice(index, 1);
    }
}
export async function scrollIntoViewIfNeeded(el, behavior = "smooth", root = null) {
    return await new Promise((resolve) => {
        const observer = new IntersectionObserver((entries) => {
            const entry = entries[0];
            if (entry?.isIntersecting && entry.intersectionRatio === 1) {
                observer.disconnect();
                resolve();
            }
            else {
                el.scrollIntoView({ behavior, block: "nearest", inline: "nearest" });
                observer.disconnect();
                resolve();
            }
        }, {
            root,
            threshold: 1.0,
        });
        observer.observe(el);
    });
}
export function isContentEditable(element) {
    if (!(element instanceof HTMLElement)) {
        return false;
    }
    const contentEditableValue = element.contentEditable.toLowerCase();
    return contentEditableValue === "true" || contentEditableValue === "plaintext-only";
}
