<script lang="ts">
	import Button from "./Button.svelte";
	import ContextMenu from "./ContextMenu.svelte";
	import Icon from "./Icon.svelte";
	import { type IconName } from "../icons/names";
	import type { Snippet } from "svelte";

	interface Props {
		showOnHover?: boolean;
		minimal?: boolean;
		contextElement?: HTMLElement;
		testId?: string;
		contextMenuTestId?: string;
		buttonClassname?: string;
		contextMenu: Snippet<[{ close: () => void }]>;
		menuSide?: "top" | "bottom" | "left" | "right";
		menuAlign?: "start" | "center" | "end";
		icon?: IconName;
		onMenuClose?: () => void;
		onMenuOpen?: () => void;
		onMenuToggle?: (isOpen: boolean, isLeftClick: boolean) => void;
	}

	let {
		showOnHover = false,
		minimal = false,
		contextElement,
		testId,
		contextMenuTestId,
		buttonClassname,
		contextMenu: contextMenuSnippet,
		menuSide = "bottom",
		menuAlign = "end",
		icon = "kebab",
		onMenuClose,
		onMenuOpen,
		onMenuToggle,
	}: Props = $props();

	let visible = $state(false);
	let buttonElement = $state<HTMLElement>();
	let isMenuOpen = $state(false);
	let menuTarget = $state<MouseEvent | HTMLElement>();

	function onMouseEnter() {
		if (!showOnHover) return;
		visible = true;
	}

	function onMouseLeave() {
		if (!showOnHover) return;
		visible = false;
	}

	function onFocus() {
		if (!showOnHover) return;
		visible = true;
	}

	function onBlur() {
		if (!showOnHover) return;
		visible = false;
	}

	function onContextMenu(e: MouseEvent) {
		e.preventDefault();
		menuTarget = e;
		isMenuOpen = true;
		onMenuToggle?.(true, false);
	}

	function onClick(e: MouseEvent) {
		e.stopPropagation();
		e.preventDefault();
		menuTarget = buttonElement;
		isMenuOpen = true;
		onMenuToggle?.(true, true);
	}

	function closeMenu() {
		isMenuOpen = false;
	}

	$effect(() => {
		if (contextElement) {
			contextElement.addEventListener("contextmenu", onContextMenu);
			contextElement.addEventListener("mouseenter", onMouseEnter);
			contextElement.addEventListener("mouseleave", onMouseLeave);
			contextElement.addEventListener("focus", onFocus);
			contextElement.addEventListener("blur", onBlur);
			return () => {
				contextElement.removeEventListener("contextmenu", onContextMenu);
				contextElement.removeEventListener("mouseenter", onMouseEnter);
				contextElement.removeEventListener("mouseleave", onMouseLeave);
				contextElement.removeEventListener("focus", onFocus);
				contextElement.removeEventListener("blur", onBlur);
			};
		}
	});
</script>

{#if showOnHover || minimal}
	<button
		bind:this={buttonElement}
		type="button"
		class={["kebab-btn", buttonClassname]}
		class:visible
		class:show-on-hover={showOnHover}
		class:minimal
		class:menu-open={isMenuOpen}
		onclick={onClick}
		oncontextmenu={onContextMenu}
		data-testid={testId}
		aria-label="Open context menu"
	>
		<Icon name={icon} size={14} />
	</button>
{:else}
	<Button
		bind:el={buttonElement}
		{testId}
		size="tag"
		icon="kebab"
		kind="ghost"
		activated={isMenuOpen}
		onclick={onClick}
		oncontextmenu={onContextMenu}
	/>
{/if}

{#if isMenuOpen}
	<ContextMenu
		target={menuTarget}
		leftClickTrigger={buttonElement}
		rightClickTrigger={contextElement}
		side={menuSide}
		align={menuAlign}
		testId={contextMenuTestId}
		onclose={() => {
			isMenuOpen = false;
			onMenuClose?.();
		}}
		onopen={() => {
			onMenuOpen?.();
		}}
	>
		{@render contextMenuSnippet({ close: closeMenu })}
	</ContextMenu>
{/if}

<style>.kebab-btn{color:var(--text-1);display:flex;padding:0 .1875rem}.kebab-btn.show-on-hover{display:none}.kebab-btn.show-on-hover.visible{display:flex;opacity:.5}.kebab-btn.show-on-hover.menu-open,.kebab-btn.show-on-hover:focus-within,.kebab-btn.show-on-hover:hover{display:flex;opacity:1}.kebab-btn.minimal{opacity:.5}.kebab-btn.minimal.menu-open,.kebab-btn.minimal:focus-within,.kebab-btn.minimal:hover{opacity:1}</style>
