<script lang="ts">
	import Icon from "./Icon.svelte";
	import { type IconName } from "../icons/names";
	import { portal } from "../utils/portal";
	import { tooltip } from "../utils/tooltipPosition";
	import { flyScale } from "../utils/transitions";
	import type { Snippet } from "svelte";

	interface Props {
		title?: string;
		size?: "small" | "medium";
		maxWidth?: string;
		iconTopOffset?: string;
		icon?: IconName;
		iconSize?: number;
		inheritColor?: boolean;
		children: Snippet;
	}

	const {
		title,
		size = "medium",
		maxWidth = "16rem",
		iconTopOffset = "10%",
		icon,
		iconSize = 16,
		children,
		inheritColor,
	}: Props = $props();

	let targetEl: HTMLElement | undefined = $state();
	let show = $state(false);
	let timeoutId: undefined | ReturnType<typeof setTimeout> = $state();
	let isHoveringCard = false; // Track if the tooltip card is hovered
	const gapDelay = 150; // Delay to allow transitioning between button and card

	function handleMouseEnter() {
		clearTimeout(timeoutId);
		timeoutId = setTimeout(() => {
			show = true;
		}, 500);
	}

	function handleMouseLeave() {
		clearTimeout(timeoutId);
		timeoutId = setTimeout(() => {
			if (!isHoveringCard) {
				show = false;
			}
		}, gapDelay);
	}

	function handleCardMouseEnter() {
		clearTimeout(timeoutId);
		isHoveringCard = true;
	}

	function handleCardMouseLeave() {
		isHoveringCard = false;
		timeoutId = setTimeout(() => {
			if (!isHoveringCard) {
				show = false;
			}
		}, gapDelay);
	}
</script>

<div
	bind:this={targetEl}
	class="wrapper {size}"
	role="tooltip"
	onmouseenter={handleMouseEnter}
	onmouseleave={handleMouseLeave}
	style:--icon-top-offset={iconTopOffset}
	style:--size={size === "small" ? "12px" : "14px"}
>
	{#if icon}
		<div class="info-custom-icon" class:inherit-color={inheritColor}>
			<Icon name={icon} size={iconSize} />
		</div>
	{:else}
		<div class="info-button" class:button-hovered={show}></div>
	{/if}

	{#if show}
		<div
			use:portal={"body"}
			use:tooltip={{
				targetEl,
				position: "bottom",
				align: "center",
			}}
			class="tooltip-container"
			role="presentation"
			transition:flyScale
			onmouseenter={handleCardMouseEnter}
			onmouseleave={handleCardMouseLeave}
		>
			<div class="tooltip-card" style:max-width={maxWidth}>
				{#if title}
					<h3 class="text-13 text-semibold tooltip-title">{title}</h3>
				{/if}
				<p class="text-12 text-body tooltip-description">
					{@render children()}
				</p>
			</div>
		</div>
	{/if}
</div>

<style>.wrapper{display:inline-flex;position:relative;transform:translateY(var(--icon-top-offset))}.info-custom-icon{color:var(--text-1);display:flex;transition:all var(--transition-fast)}.info-custom-icon.inherit-color{color:inherit}.info-button{border-radius:var(--size);box-shadow:inset 0 0 0 .09375rem var(--text-2);color:var(--text-2);height:var(--size);position:relative;transition:box-shadow var(--transition-fast);width:var(--size)}.info-button:after,.info-button:before{background-color:var(--text-2);border-radius:.125rem;content:"";left:50%;position:absolute;transform:translateX(-50%);transition:background-color var(--transition-fast)}.button-hovered{box-shadow:inset 0 0 0 .625rem var(--text-2)}.button-hovered:after,.button-hovered:before{background-color:var(--fill-gray-fg)}.wrapper.medium .info-button:before{height:.125rem;top:.1875rem;width:.125rem}.wrapper.medium .info-button:after{height:.3125rem;top:.375rem;width:.125rem}.wrapper.small .info-button:before{height:.125rem;top:.1875rem;width:.125rem}.wrapper.small .info-button:after{height:.1875rem;top:.375rem;width:.125rem}.tooltip-container{position:absolute;width:-moz-fit-content;width:fit-content;z-index:var(--z-blocker)}.tooltip-card,.tooltip-container{display:flex;flex-direction:column}.tooltip-card{background-color:var(--bg-1);border:.0625rem solid var(--border-2);border-radius:var(--radius-ml);box-shadow:var(--fx-shadow-m);gap:.25rem;padding:.75rem;width:-moz-max-content;width:max-content}.tooltip-title{color:var(--text-1)}.tooltip-description,.tooltip-title{-webkit-user-select:text;-moz-user-select:text;user-select:text}.tooltip-description{color:var(--text-2)}</style>
