<script lang="ts">
	interface Props {
		name?: string;
		small?: boolean;
		disabled?: boolean;
		value?: string;
		id?: string;
		class?: string;
		checked?: boolean;
		onchange?: (e: Event) => void;
	}

	let {
		name = "",
		small = false,
		disabled = false,
		value = "",
		id = "",
		class: className = "",
		checked = $bindable(),
		onchange,
	}: Props = $props();
</script>

<input
	type="radio"
	class="radio {className}"
	class:small
	{id}
	{value}
	{name}
	{disabled}
	{checked}
	tabindex={disabled ? -1 : 0}
	{onchange}
	onkeydown={(e) => {
		if (e.key === "Enter") {
			e.preventDefault();
			e.stopPropagation();
			checked = true;
			onchange?.(e);
		}
	}}
/>

<style>.radio{-webkit-appearance:none;-moz-appearance:none;appearance:none;background-color:var(--bg-1);border-radius:1rem;box-shadow:inset 0 0 0 .0625rem var(--border-2);cursor:pointer;height:1rem;position:relative;transition:background-color var(--transition-fast),border-color var(--transition-fast),opacity var(--transition-fast),transform var(--transition-fast);width:1rem}.radio.radio:not(:disabled):not(:checked):hover{box-shadow:inset 0 0 0 .0625rem var(--border-1)}.radio.radio:not(:disabled):not(:checked):hover:after{opacity:.2;transform:scale(.7)}.radio:not(:disabled):not(:checked):focus-visible{outline:.125rem solid var(--fill-pop-bg);outline-offset:-.125rem}.radio:disabled{background-color:var(--border-2);cursor:not-allowed;opacity:.4}.radio:checked{background-color:var(--fill-pop-bg);box-shadow:inset 0 0 0 .0625rem var(--fill-pop-bg)}.radio:checked:after{background-color:var(--clr-gray-100);opacity:1;transform:scale(1)}.radio:checked:focus-visible{outline:.125rem solid color-mix(in srgb,var(--fill-pop-bg) 60%,var(--text-1));outline-offset:-.125rem}.radio:after{background-color:var(--text-1);border-radius:1rem;content:"";height:calc(100% - .5rem);left:.25rem;opacity:0;position:absolute;top:.25rem;transform:scale(.5);transition:background-color var(--transition-fast);width:calc(100% - .5rem)}.radio.small{height:.875rem;width:.875rem}</style>
