const focusableSelectors = [
    "a[href]",
    "button:not([disabled])",
    'input:not([disabled]):not([type="hidden"])',
    "select:not([disabled])",
    "textarea:not([disabled])",
    '[tabindex]:not([tabindex="-1"])',
    '[contenteditable="true"]',
];
export function getFocusableElements(container) {
    const focusableElements = container.querySelectorAll(focusableSelectors.join(","));
    return Array.from(focusableElements)
        .filter((el) => {
        if (!(el instanceof HTMLElement))
            return false;
        return (el.offsetWidth > 0 &&
            el.offsetHeight > 0 &&
            !el.hidden &&
            getComputedStyle(el).visibility !== "hidden");
    })
        .sort((a, b) => {
        const aIndex = parseInt(a.getAttribute("tabindex") || "0") || 0;
        const bIndex = parseInt(b.getAttribute("tabindex") || "0") || 0;
        if (aIndex > 0 && bIndex === 0)
            return -1;
        if (aIndex === 0 && bIndex > 0)
            return 1;
        if (aIndex > 0 && bIndex > 0)
            return aIndex - bIndex;
        const position = a.compareDocumentPosition(b);
        return position & Node.DOCUMENT_POSITION_FOLLOWING ? -1 : 1;
    });
}
export function focusNextTabIndex(options) {
    const { container, forward, trap } = options;
    const focusableArray = getFocusableElements(container);
    const indexOf = document.activeElement instanceof HTMLElement
        ? focusableArray.indexOf(document.activeElement)
        : undefined;
    let nextIndex = forward
        ? indexOf === undefined
            ? 0
            : indexOf + 1
        : indexOf === undefined
            ? focusableArray.length - 1
            : indexOf - 1;
    if (nextIndex >= focusableArray.length) {
        if (!trap)
            return false;
        nextIndex = 0;
    }
    else if (nextIndex < 0) {
        if (!trap)
            return false;
        nextIndex = focusableArray.length - 1;
    }
    const nextElement = focusableArray[nextIndex];
    if (nextElement instanceof HTMLElement) {
        nextElement.focus();
        return true;
    }
    return false;
}
