<script lang="ts">
	import EmojiButton from "./EmojiButton.svelte";
	import { intersectionObserver } from "../../utils/intersectionObserver";
	import type { EmojiGroup, EmojiInfo } from "./utils";

	type Props = {
		group: EmojiGroup;
		handleEmojiClick: (emoji: EmojiInfo) => void;
	};

	let { group, handleEmojiClick }: Props = $props();

	let isInViewport = $state(false);
</script>

<div
	use:intersectionObserver={{
		callback: (entry) => {
			if (entry?.isIntersecting) {
				isInViewport = true;
			}
		},
		options: {
			threshold: 0.5,
			root: null,
		},
	}}
	class="emoji-picker__group"
	class:min-height={group.key !== "recently-used"}
	id="emoji-group-{group.key}"
>
	{#if isInViewport}
		{#each group.emojis as emoji}
			<EmojiButton emoji={emoji.unicode} onclick={() => handleEmojiClick(emoji)} />
		{/each}
	{/if}
</div>

<style>.emoji-picker__group{align-items:center;display:grid;grid-auto-rows:1fr;grid-template-columns:repeat(7,1fr);justify-items:center;padding:.5rem .375rem;row-gap:.25rem}.emoji-picker__group:not(:last-child){border-bottom:.0625rem solid var(--border-3)}.emoji-picker__group.min-height{min-height:12.5rem}</style>
