<script lang="ts" module>
	export interface Props {
		id?: string;
		name?: string;
		small?: boolean;
		disabled?: boolean;
		checked?: boolean;
		value?: string;
		indeterminate?: boolean;
		onclick?: (e: MouseEvent) => void;
		onchange?: (
			e: (Event | KeyboardEvent) & {
				currentTarget: EventTarget & HTMLInputElement;
			},
		) => void;
	}
</script>

<script lang="ts">
	let input = $state<HTMLInputElement>();

	let {
		id,
		name,
		small = false,
		disabled = false,
		checked = $bindable(),
		value = "",
		indeterminate = false,
		onclick,
		onchange,
	}: Props = $props();

	function getCheckmarkColor(): string {
		if (disabled) return "var(--text-2)";
		if (!checked) return "var(--text-2)";
		return "var(--fill-pop-fg)";
	}

	const checkmarkColor = $derived(getCheckmarkColor());

	function handleClick(e: MouseEvent) {
		e.stopPropagation();
		onclick?.(e);
	}

	function handleChange(e: Event & { currentTarget: EventTarget & HTMLInputElement }) {
		e.stopPropagation();
		onchange?.(e);
	}

	function handleKeydown(e: KeyboardEvent & { currentTarget: EventTarget & HTMLInputElement }) {
		if (e.key === "Enter") {
			e.preventDefault();
			e.stopPropagation();
			checked = !checked;
			onchange?.(e);
		}
	}

	$effect(() => {
		if (input) input.indeterminate = indeterminate;
	});
</script>

<div
	class="checkbox-wrapper"
	class:checked
	class:small
	class:disabled
	class:indeterminate
	style:--checkmark-color={checkmarkColor}
>
	<div class="checkbox-checkmark">
		{#if !indeterminate}
			<!-- This is a tick icon, it will be shown when the checkbox is checked -->
			<svg
				width="10"
				height="10"
				viewBox="0 0 10 10"
				fill="none"
				xmlns="http://www.w3.org/2000/svg"
			>
				<path
					d="M9 2.5L4.92139 6.74855C4.52783 7.15851 3.87217 7.15851 3.47861 6.74856L1 4.16667"
					stroke="var(--checkmark-color)"
					stroke-width="1.5"
				/>
			</svg>
		{:else}
			<svg width="8" height="2" viewBox="0 0 8 2" fill="none" xmlns="http://www.w3.org/2000/svg">
				<path d="M8 1L0 1" stroke="var(--checkmark-color)" stroke-width="1.5" />
			</svg>
		{/if}
	</div>

	<input
		bind:this={input}
		bind:checked
		tabindex="0"
		onclick={handleClick}
		onchange={handleChange}
		onkeydown={handleKeydown}
		type="checkbox"
		class="checkbox-input"
		{value}
		id={id ?? name}
		{name}
		{disabled}
	/>
</div>

