<script lang="ts">
	import Icon from "./Icon.svelte";
	import { focusable } from "../focus/focusable";
	import { type IconName } from "../icons/names";
	import { clickOutside } from "../utils/clickOutside";
	import { pxToRem } from "../utils/pxToRem";
	import { onMount, tick } from "svelte";
	import type { Snippet } from "svelte";

	interface Props {
		element?: HTMLElement;
		id?: string;
		testId?: string;
		type?: inputType;
		iconLeft?: IconName;
		iconRight?: IconName;
		customIconLeft?: Snippet;
		customIconRight?: Snippet;
		size?: "default" | "large";
		textAlign?: "left" | "center" | "right";
		value?: string;
		width?: number;
		placeholder?: string;
		helperText?: string;
		error?: string;
		label?: string;
		wide?: boolean;
		minVal?: number;
		maxVal?: number;
		showCountActions?: boolean;
		disabled?: boolean;
		readonly?: boolean;
		required?: boolean;
		spellcheck?: boolean;
		autocorrect?: boolean;
		autocomplete?: boolean;
		autofocus?: boolean;
		onclick?: (e: MouseEvent & { currentTarget: EventTarget & HTMLInputElement }) => void;
		onmousedown?: (e: MouseEvent & { currentTarget: EventTarget & HTMLInputElement }) => void;
		oninput?: (val: string) => void;
		onblur?: (e: FocusEvent & { currentTarget: EventTarget & HTMLInputElement }) => void;
		onchange?: (val: string) => void;
		onkeydown?: (e: KeyboardEvent & { currentTarget: EventTarget & HTMLInputElement }) => void;
	}

	let {
		element = $bindable(),
		id,
		testId,
		type = "text",
		iconLeft,
		iconRight,
		customIconLeft,
		customIconRight,
		value = $bindable(),
		width,
		size = "default",
		textAlign = "left",
		placeholder,
		helperText,
		error,
		label,
		wide,
		minVal,
		maxVal,
		showCountActions,
		disabled,
		readonly,
		required,
		spellcheck,
		autocorrect,
		autocomplete,
		autofocus,
		onclick,
		onmousedown,
		oninput,
		onblur,
		onchange,
		onkeydown,
	}: Props = $props();

	let showPassword = $state(false);
	let isInputValid = $state(true);
	let htmlInput: HTMLInputElement;

	// Compute whether the input has an error (external error prop or validation error)
	let hasError = $derived(!!error || !isInputValid);

	export function focus() {
		htmlInput.focus();
	}

	export function onClickOutside() {
		htmlInput.blur();
	}

	type inputType =
		| "text"
		| "password"
		| "password-non-visible"
		| "number"
		| "select"
		| "tel"
		| "url"
		| "search"
		| "date"
		| "time";

	onMount(() => {
		if (autofocus) {
			tick().then(() => {
				if (htmlInput && !htmlInput.disabled) {
					htmlInput.focus();
				}
			});
		}
	});

	function handleBlur(e: FocusEvent & { currentTarget: EventTarget & HTMLInputElement }) {
		onblur?.(e);
	}

	export async function selectAll() {
		await tick();

		if (htmlInput && !htmlInput.disabled) {
			if (htmlInput !== htmlInput.ownerDocument?.activeElement) {
				htmlInput.focus();
			}
			htmlInput.select();
		}
	}
</script>

<div
	class="textbox"
	bind:this={element}
	class:wide
	class:error={hasError}
	style:width={width ? `${pxToRem(width)}rem` : undefined}
	class:wiggle-animation={hasError}
	use:clickOutside={{ excludeElement: element, handler: onClickOutside }}
>
	{#if label}
		<label class="textbox__label text-13 text-semibold" for={id}>
			{label}
		</label>
	{/if}
	<div
		class="textbox__input-wrap"
		class:textbox__left-orient={iconLeft || customIconLeft}
		class:textbox__right-orient={iconRight || customIconRight}
		class:disabled
	>
		{#if customIconLeft}
			<div class="textbox__icon textbox__icon--left">
				{@render customIconLeft()}
			</div>
		{:else if iconLeft}
			<div class="textbox__icon textbox__icon--left">
				<Icon name={!disabled ? iconLeft : "lock"} />
			</div>
		{/if}

		{#if customIconRight}
			<div class="textbox__icon textbox__icon--right">
				{@render customIconRight()}
			</div>
		{:else if iconRight}
			<div class="textbox__icon textbox__icon--right">
				<Icon name={!disabled ? iconRight : "lock"} />
			</div>
		{/if}

		<input
			{id}
			data-testid={testId}
			{readonly}
			{required}
			{placeholder}
			{spellcheck}
			{disabled}
			autocorrect={autocorrect ? "on" : "off"}
			autocomplete={autocomplete ? "on" : "off"}
			min={minVal}
			max={maxVal}
			{...type === "password" && showPassword
				? { type: "text" }
				: { type: type === "password-non-visible" ? "password" : type }}
			class:show-count-actions={showCountActions}
			class="text-input textbox__input size-{size} {size === 'large'
				? 'text-14 text-semibold'
				: 'text-13'}"
			class:readonly={type !== "select" && readonly}
			class:error={hasError}
			style:text-align={textAlign}
			bind:value
			bind:this={htmlInput}
			use:focusable={{ button: true }}
			onblur={handleBlur}
			{onclick}
			{onmousedown}
			oninput={(e) => {
				oninput?.(e.currentTarget.value);
				isInputValid = e.currentTarget.checkValidity();
			}}
			onchange={(e) => {
				onchange?.(e.currentTarget.value);
			}}
			{onkeydown}
		/>

		{#if type === "number" && showCountActions}
			<div class="textbox__count-actions">
				<button
					type="button"
					class="textbox__count-btn"
					disabled={disabled || readonly}
					onclick={() => {
						if (disabled || readonly) return;
						htmlInput.stepDown();

						oninput?.(htmlInput.value);
						onchange?.(htmlInput.value);

						isInputValid = htmlInput.checkValidity();
					}}
				>
					<Icon name="minus" />
				</button>
				<button
					type="button"
					class="textbox__count-btn"
					disabled={disabled || readonly}
					onclick={() => {
						if (disabled || readonly) return;
						htmlInput.stepUp();

						oninput?.(htmlInput.value);
						onchange?.(htmlInput.value);

						isInputValid = htmlInput.checkValidity();
					}}
				>
					<Icon name="plus" />
				</button>
			</div>
		{/if}

		{#if type === "password"}
			<button
				type="button"
				class="textbox__show-hide-icon"
				disabled={disabled || readonly}
				onclick={() => {
					if (disabled || readonly) return;
					showPassword = !showPassword;
					htmlInput.focus();
				}}
			>
				<Icon name={showPassword ? "eye" : "eye-closed"} />
			</button>
		{/if}
	</div>

	{#if error}
		<p class="text-11 text-body textbox__error-text">{error}</p>
	{:else if helperText}
		<p class="text-11 text-body textbox__helper-text">{helperText}</p>
	{/if}
</div>

