<script lang="ts" module>
	// import type { Snippet } from 'svelte';
	export interface Props {
		title: string;
		aiMessage?: string;
		sha: string;
		upstreamSha?: string;
		date: Date;
		author?: string;
		url?: string;
		onlyContent?: boolean;
		isDone?: boolean;
		onCopy?: () => void;
		onCopyUpstream?: () => void;
		onOpen?: (url: string) => void;
		loading?: boolean;
	}
</script>

<script lang="ts">
	import CopyButton from "./CopyButton.svelte";
	import Icon from "./Icon.svelte";
	import SimpleCommitRowSkeleton from "./SimpleCommitRowSkeleton.svelte";
	import { getTimeAndAuthor } from "../utils/getTimeAndAuthor";

	const {
		title,
		aiMessage,
		sha,
		author,
		date,
		url,
		onlyContent,
		upstreamSha,
		isDone,
		onCopy,
		onCopyUpstream,
		onOpen,
		loading,
	}: Props = $props();
</script>

{#if loading}
	<SimpleCommitRowSkeleton {onlyContent} />
{:else}
	<div class="simple-commit-item no-select" class:content-only={onlyContent}>
		{#if !onlyContent}
			{#if isDone}
				<Icon name="tick" color="var(--fill-safe-bg)" />
			{:else}
				<Icon name="commit" />
			{/if}
		{/if}
		<div class="content">
			<span class="title text-13 text-semibold">
				{title}
			</span>

			{#if aiMessage}
				<div class="ai-message text-12 text-body">
					<p>{aiMessage}</p>
				</div>
			{/if}

			<div class="details text-11">
				<CopyButton class="details-btn" text={sha} onclick={onCopy} />

				{#if upstreamSha}
					<span class="details-divider">•</span>
					<CopyButton
						class="details-btn"
						text={upstreamSha}
						prefix="upstream"
						onclick={onCopyUpstream}
					/>
				{/if}

				{#if url && onOpen}
					<span class="details-divider">•</span>
					<button type="button" class="details-btn link-btn" onclick={() => onOpen(url)}>
						<span>Open</span>
						<Icon name="arrow-up-righ" />
					</button>
				{/if}

				<span class="details-divider">•</span>
				<span class="truncate">{getTimeAndAuthor(date, author)}</span>
			</div>
		</div>
	</div>
{/if}

