import { determinePlatform } from "./platform";
export function keysStringToArr(keys) {
    const platform = determinePlatform(navigator.userAgent);
    return keys.split("+").map((key) => {
        if (key === "Shift")
            return "⇧";
        if (key === "$mod") {
            if (platform === "macos") {
                return "⌘";
            }
            else {
                return "Ctrl";
            }
        }
        return key;
    });
}
